import React from "react";
import { View, Pressable } from "react-native";
import Animated, { useAnimatedStyle, useSharedValue, withTiming } from "react-native-reanimated";
import { Text } from "../../../UI";

type Props = {
    label?: any;
    value?: string;
    isFocused: boolean;
    disabled?: boolean;
    onFocusRequest?: () => void;
    children: React.ReactNode;
};

export function FloatLabelNative({ label, value, isFocused, disabled, onFocusRequest, children }: Props) {
    const raised = isFocused || !!value;
    const t = useSharedValue(raised ? 1 : 0);

    React.useEffect(() => {
        t.value = withTiming(raised ? 1 : 0, { duration: 140 });
    }, [raised]);

    const anim = useAnimatedStyle(() => {
        // small + simple; rely on className/style elsewhere
        return {
            transform: [{ translateY: (1 - t.value) * 25 },{ translateX: (1 - t.value) * 11 }, { scale: 1 - t.value * 0.12 }],
            opacity: 0.9,
        };
    });

    if (!label) return <>{children}</>;

    return (
        <Pressable disabled={disabled} onPress={onFocusRequest} style={{ width: "100%" }}>
            <View style={{ width: "100%", position: "relative" }}>
                <Animated.View style={[{ position: "absolute", left: 0, top: -5, zIndex: 2 }, anim]}>
                    <Text fontSize={12}>{label}</Text>
                </Animated.View>
                <View style={{ paddingTop: 14 }}>
                    {children}
                </View>
            </View>
        </Pressable>
    );
}
